@page "/category/{Slug}"

<PageTitle>@GetCategoryName() - RecipeShare</PageTitle>

<h1>@GetCategoryName()</h1>
<p><a href="/">← Back to Categories</a></p>

@if (GetRecipes().Any())
{
    <div class="row">
        @foreach (var recipe in GetRecipes())
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text text-muted">@recipe.Summary</p>
                        <a href="@($"recipe/{recipe.Id}")" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}
else
{
    <p class="text-muted">No recipes found in this category yet.</p>
}

@code {
    [Parameter]
    public string Slug { get; set; } = "";

    private string GetCategoryName() => Slug switch
    {
        "breakfast" => "Breakfast",
        "main-courses" => "Main Courses",
        "desserts" => "Desserts",
        "soups-salads" => "Soups & Salads",
        "vegetarian" => "Vegetarian",
        "quick-easy" => "Quick & Easy",
        _ => "Category"
    };

    private List<RecipeSummary> GetRecipes() => Slug switch
    {
        "breakfast" => new()
        {
            new(1, "Fluffy Pancakes", "Classic buttermilk pancakes with maple syrup."),
            new(2, "Avocado Toast", "Crispy toast topped with smashed avocado and seasoning.")
        },
        "main-courses" => new()
        {
            new(3, "Spaghetti Bolognese", "Rich meat sauce over perfectly cooked pasta."),
            new(4, "Grilled Chicken", "Herb-marinated chicken breast with roasted vegetables.")
        },
        "desserts" => new()
        {
            new(5, "Chocolate Lava Cake", "Warm cake with a molten chocolate center."),
            new(6, "Classic Tiramisu", "Layers of coffee-soaked ladyfingers and mascarpone.")
        },
        "soups-salads" => new()
        {
            new(7, "Tomato Basil Soup", "Creamy tomato soup with fresh basil."),
            new(8, "Caesar Salad", "Crisp romaine with parmesan and homemade dressing.")
        },
        "vegetarian" => new()
        {
            new(9, "Mushroom Risotto", "Creamy arborio rice with wild mushrooms."),
            new(10, "Veggie Stir Fry", "Colorful vegetables in a savory ginger sauce.")
        },
        "quick-easy" => new()
        {
            new(11, "Caprese Sandwich", "Fresh mozzarella, tomato, and basil on ciabatta."),
            new(12, "Garlic Shrimp", "Sautéed shrimp in garlic butter, ready in 15 minutes.")
        },
        _ => new()
    };

    private record RecipeSummary(int Id, string Title, string Summary);
}

@rendermode InteractiveServer

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= currentRating ? "filled" : "")"
              @onclick="() => Rate(star)"
              role="button"
              title="@star star(s)">
            @(star <= currentRating ? "★" : "☆")
        </span>
    }
    @if (currentRating > 0)
    {
        <span class="ms-2 text-muted">You rated this @currentRating/5</span>
    }
    else
    {
        <span class="ms-2 text-muted">Click to rate</span>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int currentRating;

    private void Rate(int stars)
    {
        currentRating = stars;
    }
}

@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Thank you!</h4>
        <p>Your recipe "<strong>@model.Title</strong>" has been submitted for review.</p>
        <a href="/" class="btn btn-primary">Back to Home</a>
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="model.Title" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => model.Title" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="model.Ingredients"
                           placeholder="One ingredient per line, e.g.:&#10;2 cups flour&#10;1 cup sugar&#10;3 eggs" />
            <ValidationMessage For="() => model.Ingredients" />
            <small class="text-muted">Enter one ingredient per line.</small>
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Preparation Steps</label>
            <InputTextArea id="steps" class="form-control" rows="8" @bind-Value="model.Steps"
                           placeholder="One step per line, e.g.:&#10;Preheat oven to 350°F.&#10;Mix dry ingredients together.&#10;Add wet ingredients and stir." />
            <ValidationMessage For="() => model.Steps" />
            <small class="text-muted">Enter one step per line.</small>
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeSubmission model = new();
    private bool submitted;

    private void HandleSubmit()
    {
        submitted = true;
    }

    private class RecipeSubmission
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please enter a recipe title.")]
        [System.ComponentModel.DataAnnotations.StringLength(100, MinimumLength = 3, ErrorMessage = "Title must be between 3 and 100 characters.")]
        public string Title { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please list the ingredients.")]
        public string Ingredients { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please describe the preparation steps.")]
        public string Steps { get; set; } = "";
    }
}

